t.script:
//
(function() {
    'use strict';

    // Único ID visible en el dropdown: Ciudad de México (CMX, estándar ISO)
    var CDMX_STATE_ID = 493;

    function isCDMX(optionValue) {
        return parseInt(optionValue) === CDMX_STATE_ID;
    }

    function filterStatesToCDMX() {
        var stateSelect = document.getElementById('state_id');
        if (!stateSelect) { return; }

        var options = Array.from(stateSelect.options);
        var cdmxOption = null;

        options.forEach(function(opt) {
            if (opt.value === '') {
                return;
            }
            if (isCDMX(opt.value)) {
                cdmxOption = opt;
            } else {
                stateSelect.removeChild(opt);
            }
        });

        // Auto-seleccionar Ciudad de México
        if (cdmxOption) {
            cdmxOption.selected = true;
            stateSelect.dispatchEvent(new Event('change', { bubbles: true }));
        }

        // Deshabilitar visualmente el select (solo hay una opción)
        stateSelect.style.pointerEvents = 'none';
        stateSelect.style.backgroundColor = '#e9ecef';
    }

    // Interceptar fetch para filtrar la respuesta de country_infos
    var _originalFetch = window.fetch;
    window.fetch = function(url, fetchOptions) {
        return _originalFetch.apply(this, arguments).then(function(response) {
            var urlStr = typeof url === 'string' ? url : (url.url || '');
            if (urlStr.indexOf('country_infos') !== -1) {
                return response.json().then(function(data) {
                    if (data) {
                        if (Array.isArray(data.states)) {
                            data.states = data.states.filter(function(s) {
                                return s[0] === CDMX_STATE_ID;
                            });
                        }
                    }
                    return new Response(JSON.stringify(data), {
                        status: response.status,
                        statusText: response.statusText,
                        headers: { 'Content-Type': 'application/json' }
                    });
                });
            }
            return response;
        });
    };

    // Ejecutar en DOMContentLoaded y observar cambios dinámicos
    document.addEventListener('DOMContentLoaded', function() {
        filterStatesToCDMX();

        var observer = new MutationObserver(function(mutations) {
            mutations.forEach(function(mutation) {
                mutation.addedNodes.forEach(function(node) {
                    if (node.nodeType !== 1) { return; }
                    var sel = null;
                    if (node.id === 'state_id') {
                        sel = node;
                    } else if (node.querySelector) {
                        sel = node.querySelector('#state_id');
                    }
                    if (sel) { filterStatesToCDMX(); }
                });
                if (mutation.target) {
                    if (mutation.target.id === 'state_id') {
                        filterStatesToCDMX();
                    }
                }
            });
        });

        observer.observe(document.body, { childList: true, subtree: true });
    });

}());
//
